queries.sparql:
PREFIX : <http://ambrosia.example.org/journalism#>
PREFIX p: <http://ambrosia.example.org/journalism/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?o0 WHERE {
  {
    ?advertising a :Advertising .
    ?advertising p:Type ?type .
    ?advertising p:Magazine ?magazine_f .
    FILTER(STR(?magazine_f) = "Good Housekeeping")
    BIND(?type AS ?o0)
  }
  UNION
  {
    ?subscriptions a :Subscriptions .
    ?subscriptions p:Type ?type .
    ?subscriptions p:Magazine ?magazine_f .
    FILTER(STR(?magazine_f) = "Good Housekeeping")
    BIND(?type AS ?o0)
  }
}

